import React, { useState } from "react";

function App() {
  return (
    <div style={page}>

      {/* FORM CARD */}

      <div style={formCard}>
        <h2 style={{marginBottom:"20px"}}>Log HCP Interaction</h2>

        <input placeholder="HCP Name" style={input}/>

        <select style={input}>
          <option>Interaction Type</option>
          <option>Meeting</option>
          <option>Call</option>
        </select>

        <input type="date" style={input}/>

        <textarea placeholder="Topics Discussed" style={input}></textarea>

        <select style={input}>
          <option>Doctor Sentiment</option>
          <option>Positive</option>
          <option>Neutral</option>
          <option>Negative</option>
        </select>

        <textarea placeholder="Follow-up Actions" style={input}></textarea>

        <button style={button}>Log Interaction</button>

      </div>


      {/* AI ASSISTANT */}

      <div style={aiCard}>

        <h3>AI Assistant</h3>

        <p style={{color:"#aaa"}}>
          Describe the interaction and AI will help log it.
        </p>

        <textarea
          placeholder="Example: Met Dr Sharma and discussed Product X..."
          style={chat}
        />

        <button style={aiButton}>
          Ask AI
        </button>

      </div>

    </div>
  );
}


/* PAGE */

const page = {
  height:"100vh",
  display:"flex",
  justifyContent:"center",
  alignItems:"center",
  gap:"40px",
  background:"#0f0f0f",
  fontFamily:"Inter, sans-serif"
};


/* FORM CARD */

const formCard = {
  width:"420px",
  padding:"30px",
  borderRadius:"16px",
  background:"#181818",
  boxShadow:"0 0 30px rgba(0,0,0,0.8)",
  color:"white"
};


/* AI CARD */

const aiCard = {
  width:"350px",
  padding:"25px",
  borderRadius:"16px",
  background:"#181818",
  boxShadow:"0 0 30px rgba(0,0,0,0.8)",
  color:"white"
};


/* INPUT */

const input = {
  width:"100%",
  padding:"12px",
  marginBottom:"15px",
  borderRadius:"8px",
  border:"1px solid #333",
  background:"#111",
  color:"white"
};


/* BUTTON */

const button = {
  width:"100%",
  padding:"12px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#ff4d6d,#ff758c)",
  color:"white",
  fontSize:"15px",
  cursor:"pointer"
};


const aiButton = {
  width:"100%",
  padding:"12px",
  marginTop:"10px",
  border:"none",
  borderRadius:"8px",
  background:"linear-gradient(90deg,#00c6ff,#0072ff)",
  color:"white",
  cursor:"pointer"
};


/* CHAT */

const chat = {
  width:"100%",
  height:"120px",
  padding:"10px",
  borderRadius:"8px",
  border:"1px solid #333",
  background:"#111",
  color:"white",
  marginTop:"10px"
};

export default App;
